  delete(key: string) {
    if (!this.map.has(key)) {
      return;
    }
    const node = this.map.get(key)!;
    this.removeNode(node);
    this.map.delete(key);
  }

  toArray(): string[] {
    const keys: string[] = [];
    let current = this.head.next;
    while (current !== this.tail) {
      keys.push(current.key);
      current = current.next;
    }
    return keys;
  }
}

